   343→      ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
   344→      if (auto header_entry = headers.get(key); header_entry.empty()) {
   345→        ENVOY_STREAM_LOG(trace, "ext_authz filter added header(s) to the encoded response:",
   346→                         *encoder_callbacks_);
