   226→Http::FilterHeadersStatus Filter::decodeHeaders(Http::RequestHeaderMap& headers, bool end_stream) {
   227→  Router::RouteConstSharedPtr route = decoder_callbacks_->route();
   228→  const auto per_route_flags = getPerRouteFlags(route);
   229→  skip_check_ = per_route_flags.skip_check_;
   230→  if (skip_check_) {
   231→    return Http::FilterHeadersStatus::Continue;
   232→  }
   233→
   234→  if (!config_->filterEnabled(decoder_callbacks_->streamInfo().dynamicMetadata())) {
   235→    stats_.disabled_.inc();
   236→    if (config_->denyAtDisable()) {
   237→      ENVOY_STREAM_LOG(trace, "ext_authz filter is disabled. Deny the request.",
   238→                       *decoder_callbacks_);
   239→      decoder_callbacks_->streamInfo().setResponseFlag(
   240→          StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
   241→      decoder_callbacks_->sendLocalReply(
   242→          config_->statusOnError(), EMPTY_STRING, nullptr, absl::nullopt,
   243→          Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
   244→      return Http::FilterHeadersStatus::StopIteration;
   245→    }
   246→    return Http::FilterHeadersStatus::Continue;
   247→  }
   248→
   249→  request_headers_ = &headers;
   250→  const auto check_settings = per_route_flags.check_settings_;
   251→  buffer_data_ = (config_->withRequestBody() || check_settings.has_with_request_body()) &&
   252→                 !check_settings.disable_request_body_buffering() &&
   253→                 !(end_stream || Http::Utility::isWebSocketUpgradeRequest(headers) ||
   254→                   Http::Utility::isH2UpgradeRequest(headers));
   255→
   256→  max_request_bytes_ = config_->maxRequestBytes();
   257→  if (buffer_data_) {
   258→    ENVOY_STREAM_LOG(debug, "ext_authz filter is buffering the request", *decoder_callbacks_);
   259→
   260→    allow_partial_message_ = check_settings.has_with_request_body()
   261→                                 ? check_settings.with_request_body().allow_partial_message()
   262→                                 : config_->allowPartialMessage();
   263→    if (check_settings.has_with_request_body()) {
   264→      max_request_bytes_ = check_settings.with_request_body().max_request_bytes();
   265→    }
   266→    if (!allow_partial_message_) {
   267→      decoder_callbacks_->setDecoderBufferLimit(max_request_bytes_);
   268→    }
   269→    return Http::FilterHeadersStatus::StopIteration;
   270→  }
   271→
   272→  // Initiate a call to the authorization server since we are not disabled.
   273→  initiateCall(headers);
   274→  return filter_return_ == FilterReturn::StopDecoding
   275→             ? Http::FilterHeadersStatus::StopAllIterationAndWatermark
   276→             : Http::FilterHeadersStatus::Continue;
   277→}
   278→
   279→Http::FilterDataStatus Filter::decodeData(Buffer::Instance& data, bool end_stream) {
   280→  if (buffer_data_ && !skip_check_) {
   281→    const bool buffer_is_full = isBufferFull(data.length());
   282→    if (end_stream || buffer_is_full) {
   283→      ENVOY_STREAM_LOG(debug, "ext_authz filter finished buffering the request since {}",
   284→                       *decoder_callbacks_, buffer_is_full ? "buffer is full" : "stream is ended");
   285→      // Make sure data is available in initiateCall.
   286→      decoder_callbacks_->addDecodedData(data, true);
   287→      initiateCall(*request_headers_);
   288→      return filter_return_ == FilterReturn::StopDecoding
   289→                 ? Http::FilterDataStatus::StopIterationAndWatermark
   290→                 : Http::FilterDataStatus::Continue;
   291→    } else {
   292→      return Http::FilterDataStatus::StopIterationAndBuffer;
   293→    }
   294→  }
   295→
   296→  return Http::FilterDataStatus::Continue;
   297→}
   298→
   299→Http::FilterTrailersStatus Filter::decodeTrailers(Http::RequestTrailerMap&) {
   300→  if (buffer_data_ && !skip_check_) {
   301→    if (filter_return_ != FilterReturn::StopDecoding) {
   302→      ENVOY_STREAM_LOG(debug, "ext_authz filter finished buffering the request",
   303→                       *decoder_callbacks_);
   304→      initiateCall(*request_headers_);
   305→    }
   306→    return filter_return_ == FilterReturn::StopDecoding ? Http::FilterTrailersStatus::StopIteration
   307→                                                        : Http::FilterTrailersStatus::Continue;
   308→  }
   309→
   310→  return Http::FilterTrailersStatus::Continue;
   311→}
