   392→CheckResult Filter::validateAndCheckDecoderHeaderMutation(
   393→    Filters::Common::MutationRules::CheckOperation operation, absl::string_view key,
   394→    absl::string_view value) const {
   395→  if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
   396→                                       !Http::HeaderUtility::headerValueIsValid(value))) {
   397→    return CheckResult::FAIL;
   398→  }
   399→  // Check header mutation is valid according to configured decoder mutation rules.
   400→  return config_->checkDecoderHeaderMutation(operation, Http::LowerCaseString(key), value);
   401→}
