   403→void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
   404→  state_ = State::Complete;
   405→  using Filters::Common::ExtAuthz::CheckStatus;
   406→  Stats::StatName empty_stat_name;
   407→
   408→  if (!response->dynamic_metadata.fields().empty()) {
   409→    if (!config_->enableDynamicMetadataIngestion()) {
   410→      ENVOY_STREAM_LOG(trace,
   411→                       "Response is trying to inject dynamic metadata, but dynamic metadata "
   412→                       "ingestion is disabled. Ignoring...",
   413→                       *decoder_callbacks_);
   414→      stats_.ignored_dynamic_metadata_.inc();
   415→    } else {
   416→      // Add duration of call to dynamic metadata if applicable
   417→      if (start_time_.has_value() && response->status == CheckStatus::OK) {
   418→        ProtobufWkt::Value ext_authz_duration_value;
   419→        auto duration =
   420→            decoder_callbacks_->dispatcher().timeSource().monotonicTime() - start_time_.value();
   421→        ext_authz_duration_value.set_number_value(
   422→            std::chrono::duration_cast<std::chrono::milliseconds>(duration).count());
   423→        (*response->dynamic_metadata.mutable_fields())["ext_authz_duration"] =
   424→            ext_authz_duration_value;
   425→      }
   426→      decoder_callbacks_->streamInfo().setDynamicMetadata("envoy.filters.http.ext_authz",
   427→                                                          response->dynamic_metadata);
   428→    }
   429→  }
   430→
   431→  switch (response->status) {
   432→  case CheckStatus::OK: {
   433→    // Any changes to request headers or query parameters can affect how the request is going to be
   434→    // routed. If we are changing the headers we also need to clear the route
   435→    // cache.
   436→    if (config_->clearRouteCache() &&
   437→        (!response->headers_to_set.empty() || !response->headers_to_append.empty() ||
   438→         !response->headers_to_remove.empty() || !response->query_parameters_to_set.empty() ||
   439→         !response->query_parameters_to_remove.empty())) {
   440→      ENVOY_STREAM_LOG(debug, "ext_authz is clearing route cache", *decoder_callbacks_);
   441→      decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
   442→    }
   443→
   444→    ENVOY_STREAM_LOG(trace,
   445→                     "ext_authz filter added header(s) to the request:", *decoder_callbacks_);
   446→    for (const auto& [key, value] : response->headers_to_set) {
   447→      CheckResult check_result = validateAndCheckDecoderHeaderMutation(
   448→          Filters::Common::MutationRules::CheckOperation::SET, key, value);
   449→      switch (check_result) {
   450→      case CheckResult::OK:
   451→        ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
   452→        request_headers_->setCopy(Http::LowerCaseString(key), value);
   453→        break;
   454→      case CheckResult::IGNORE:
   455→        ENVOY_STREAM_LOG(trace, "Ignoring invalid header to set '{}':'{}'.", *decoder_callbacks_,
   456→                         key, value);
   457→        break;
   458→      case CheckResult::FAIL:
   459→        ENVOY_STREAM_LOG(trace, "Rejecting invalid header to set '{}':'{}'.", *decoder_callbacks_,
   460→                         key, value);
   461→        rejectResponse();
   462→        return;
   463→      }
   464→    }
   465→    for (const auto& [key, value] : response->headers_to_add) {
   466→      CheckResult check_result = validateAndCheckDecoderHeaderMutation(
   467→          Filters::Common::MutationRules::CheckOperation::SET, key, value);
   468→      switch (check_result) {
   469→      case CheckResult::OK:
   470→        ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
   471→        request_headers_->addCopy(Http::LowerCaseString(key), value);
   472→        break;
   473→      case CheckResult::IGNORE:
   474→        ENVOY_STREAM_LOG(trace, "Ignoring invalid header to add '{}':'{}'.", *decoder_callbacks_,
   475→                         key, value);
   476→        break;
   477→      case CheckResult::FAIL:
   478→        ENVOY_STREAM_LOG(trace, "Rejecting invalid header to add '{}':'{}'.", *decoder_callbacks_,
   479→                         key, value);
   480→        rejectResponse();
   481→        return;
   482→      }
   483→    }
   484→    for (const auto& [key, value] : response->headers_to_append) {
   485→      CheckResult check_result = validateAndCheckDecoderHeaderMutation(
   486→          Filters::Common::MutationRules::CheckOperation::APPEND, key, value);
   487→      switch (check_result) {
   488→      case CheckResult::OK: {
   489→        ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
   490→        Http::LowerCaseString lowercase_key(key);
   491→        const auto header_to_modify = request_headers_->get(lowercase_key);
   492→        // TODO(dio): Add a flag to allow appending non-existent headers, without setting it
   493→        // first (via `headers_to_add`). For example, given:
   494→        // 1. Original headers {"original": "true"}
   495→        // 2. Response headers from the authorization servers {{"append": "1"}, {"append":
   496→        // "2"}}
   497→        //
   498→        // Currently it is not possible to add {{"append": "1"}, {"append": "2"}} (the
   499→        // intended combined headers: {{"original": "true"}, {"append": "1"}, {"append":
   500→        // "2"}}) to the request to upstream server by only sets `headers_to_append`.
   501→        if (!header_to_modify.empty()) {
   502→          ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
