   540→      Http::LowerCaseString lowercase_key(key);
   541→      switch (config_->checkDecoderHeaderMutation(CheckOperation::REMOVE, lowercase_key,
   542→                                                  EMPTY_STRING)) {
   543→      case CheckResult::OK:
   544→        ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
