   547→      case CheckResult::IGNORE:
   548→        ENVOY_STREAM_LOG(trace, "Ignoring disallowed header removal '{}'.", *decoder_callbacks_,
   549→                         key);
   550→        break;
   551→      case CheckResult::FAIL:
   552→        ENVOY_STREAM_LOG(trace, "Rejecting disallowed header removal '{}'.", *decoder_callbacks_,
   553→                         key);
