   559→    if (!response->response_headers_to_add.empty()) {
   560→      ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
   561→                       *decoder_callbacks_, response->response_headers_to_add.size());
   562→      for (const auto& [key, value] : response->response_headers_to_add) {
   563→        if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
   564→                                             !Http::HeaderUtility::headerValueIsValid(value))) {
   565→          ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
   566→                           value);
   567→          rejectResponse();
   568→          return;
   569→        }
   570→      }
