   584→          return;
   585→        }
   586→      }
   587→      response_headers_to_set_ = Http::HeaderVector{response->response_headers_to_set.begin(),
   588→                                                    response->response_headers_to_set.end()};
   589→    }
   590→
   591→    if (!response->response_headers_to_add_if_absent.empty()) {
   592→      ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
   593→                       *decoder_callbacks_, response->response_headers_to_add_if_absent.size());
   594→      for (const auto& [key, value] : response->response_headers_to_add_if_absent) {
   595→        if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
   596→                                             !Http::HeaderUtility::headerValueIsValid(value))) {
   597→          ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
   598→                           value);
   599→          rejectResponse();
   600→          return;
   601→        }
   602→      }
   603→      response_headers_to_add_if_absent_ =
   604→          Http::HeaderVector{response->response_headers_to_add_if_absent.begin(),
   605→                             response->response_headers_to_add_if_absent.end()};
   606→    }
   607→
   608→    if (!response->response_headers_to_overwrite_if_exists.empty()) {
   609→      ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
   610→                       *decoder_callbacks_,
   611→                       response->response_headers_to_overwrite_if_exists.size());
   612→      for (const auto& [key, value] : response->response_headers_to_overwrite_if_exists) {
   613→        if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
   614→                                             !Http::HeaderUtility::headerValueIsValid(value))) {
   615→          ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
   616→                           value);
   617→          rejectResponse();
   618→          return;
   619→        }
   620→      }
   621→      response_headers_to_overwrite_if_exists_ =
   622→          Http::HeaderVector{response->response_headers_to_overwrite_if_exists.begin(),
   623→                             response->response_headers_to_overwrite_if_exists.end()};
   624→    }
   625→
   626→    absl::optional<Http::Utility::QueryParamsMulti> modified_query_parameters;
   627→    if (!response->query_parameters_to_set.empty()) {
   628→      modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
   629→          request_headers_->Path()->value().getStringView());
   630→      ENVOY_STREAM_LOG(
   631→          trace, "ext_authz filter set query parameter(s) on the request:", *decoder_callbacks_);
   632→      for (const auto& [key, value] : response->query_parameters_to_set) {
   633→        if (config_->validateMutations() &&
   634→            (!Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(key) ||
   635→             !Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(value))) {
   636→          ENVOY_STREAM_LOG(trace, "Rejected invalid query parameter {}={}.", *decoder_callbacks_,
   637→                           key, value);
