   676→  }
   677→
   678→  case CheckStatus::Denied: {
   679→    ENVOY_STREAM_LOG(trace, "ext_authz filter rejected the request. Response status code: '{}'",
   680→                     *decoder_callbacks_, enumToInt(response->status_code));
   681→    stats_.denied_.inc();
   682→
   683→    if (cluster_) {
   684→      config_->incCounter(cluster_->statsScope(), config_->ext_authz_denied_);
   685→      if (config_->chargeClusterResponseStats()) {
   686→        Http::CodeStats::ResponseStatInfo info{config_->scope(),
   687→                                               cluster_->statsScope(),
   688→                                               empty_stat_name,
   689→                                               enumToInt(response->status_code),
   690→                                               true,
   691→                                               empty_stat_name,
   692→                                               empty_stat_name,
   693→                                               empty_stat_name,
   694→                                               empty_stat_name,
   695→                                               empty_stat_name,
   696→                                               false};
   697→        config_->httpContext().codeStats().chargeResponseStat(info, false);
   698→      }
   699→    }
   700→
   701→    // Check headers are valid.
   702→    if (config_->validateMutations()) {
   703→      for (const auto& [key, value] : response->headers_to_set) {
   704→        if (!Http::HeaderUtility::headerNameIsValid(key) ||
   705→            !Http::HeaderUtility::headerValueIsValid(value)) {
   706→          ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
   707→                           value);
   708→          rejectResponse();
   709→          return;
   710→        }
   711→      }
   712→    }
   713→
   714→    // setResponseFlag must be called before sendLocalReply
   715→    decoder_callbacks_->streamInfo().setResponseFlag(
   716→        StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
   717→    decoder_callbacks_->sendLocalReply(
   718→        response->status_code, response->body,
   719→        [&headers = response->headers_to_set,
   720→         &callbacks = *decoder_callbacks_](Http::HeaderMap& response_headers) -> void {
   721→          ENVOY_STREAM_LOG(trace,
   722→                           "ext_authz filter added header(s) to the local response:", callbacks);
   723→          // Firstly, remove all headers requested by the ext_authz filter, to ensure that they will
   724→          // override existing headers.
   725→          for (const auto& [key, _] : headers) {
   726→            response_headers.remove(Http::LowerCaseString(key));
   727→          }
   728→          // Then set all of the requested headers, allowing the same header to be set multiple
   729→          // times, e.g. `Set-Cookie`.
   730→          for (const auto& [key, value] : headers) {
