   735→        absl::nullopt, Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzDenied);
   736→    break;
   737→  }
   738→
   739→  case CheckStatus::Error: {
   740→    if (cluster_) {
   741→      config_->incCounter(cluster_->statsScope(), config_->ext_authz_error_);
   742→    }
