   155→  std::vector<Matchers::StringMatcherPtr> matchers(
   156→      CheckRequestUtils::createStringMatchers(list, context));
   157→
   158→  // If list is empty, all authorization response headers, except Host, should be added to
   159→  // the client response.
   160→  if (matchers.empty()) {
   161→    envoy::type::matcher::v3::StringMatcher matcher;
   162→    matcher.set_exact(Http::Headers::get().Host.get());
