   203→
   204→// Client
   205→void RawHttpClientImpl::check(RequestCallbacks& callbacks,
   206→                              const envoy::service::auth::v3::CheckRequest& request,
   207→                              Tracing::Span& parent_span,
   208→                              const StreamInfo::StreamInfo& stream_info) {
   209→  ASSERT(callbacks_ == nullptr);
   210→  callbacks_ = &callbacks;
   211→
   212→  Http::RequestHeaderMapPtr headers;
   213→
   214→  const auto& http_request = request.attributes().request().http();
   215→  const auto& http_request_body =
   216→      http_request.body().empty() ? http_request.raw_body() : http_request.body();
   217→
   218→  uint64_t request_length = http_request_body.size();
   219→
   220→  if (request_length > 0) {
   221→    headers = Http::createHeaderMap<Http::RequestHeaderMapImpl>(
   222→        {{Http::Headers::get().ContentLength, std::to_string(request_length)}});
   223→  } else {
   224→    headers = Http::createHeaderMap<Http::RequestHeaderMapImpl>(lengthZeroHeader());
   225→  }
   226→
   227→  if (config_->encodeRawHeaders()) {
   228→    for (const auto& header : http_request.header_map().headers()) {
   229→      const Http::LowerCaseString key{header.key()};
   230→
   231→      // Skip setting content-length header since it is already configured at initialization.
   232→      if (key == Http::Headers::get().ContentLength) {
   233→        continue;
   234→      }
   235→
   236→      if (key == Http::Headers::get().Path && !config_->pathPrefix().empty()) {
   237→        headers->addCopy(key, absl::StrCat(config_->pathPrefix(), header.raw_value()));
   238→      } else {
   239→        headers->addCopy(key, header.raw_value());
   240→      }
   241→    }
   242→  } else {
   243→    for (const auto& header : http_request.headers()) {
   244→      const Http::LowerCaseString key{header.first};
   245→
   246→      // Skip setting content-length header since it is already configured at initialization.
   247→      if (key == Http::Headers::get().ContentLength) {
   248→        continue;
   249→      }
   250→
   251→      if (key == Http::Headers::get().Path && !config_->pathPrefix().empty()) {
   252→        headers->addCopy(key, absl::StrCat(config_->pathPrefix(), header.second));
   253→      } else {
   254→        headers->addCopy(key, header.second);
   255→      }
   256→    }
   257→  }
   258→
   259→  config_->requestHeaderParser().evaluateHeaders(*headers, stream_info);
   260→
   261→  Http::RequestMessagePtr message =
   262→      std::make_unique<Envoy::Http::RequestMessageImpl>(std::move(headers));
   263→  if (request_length > 0) {
   264→    message->body().add(http_request_body);
   265→  }
   266→
   267→  const std::string& cluster = config_->cluster();
   268→
   269→  // It's possible that the cluster specified in the filter configuration no longer exists due to a
   270→  // CDS removal.
   271→  const auto thread_local_cluster = cm_.getThreadLocalCluster(cluster);
   272→  if (thread_local_cluster == nullptr) {
   273→    // TODO(dio): Add stats related to this.
   274→    ENVOY_LOG(debug, "ext_authz cluster '{}' does not exist", cluster);
   275→    callbacks_->onComplete(std::make_unique<Response>(errorResponse()));
   276→    callbacks_ = nullptr;
   277→  } else {
   278→    // Do not enforce a sampling decision on this span; instead keep the parent's sampling status.
   279→    auto options = Http::AsyncClient::RequestOptions()
   280→                       .setTimeout(config_->timeout())
   281→                       .setParentSpan(parent_span)
   282→                       .setChildSpanName(config_->tracingName())
   283→                       .setSampled(absl::nullopt);
   284→
   285→    options.setSendXff(false);
   286→
   287→    request_ = thread_local_cluster->httpAsyncClient().send(std::move(message), *this, options);
   288→  }
   289→}
