   291→void RawHttpClientImpl::onSuccess(const Http::AsyncClient::Request&,
   292→                                  Http::ResponseMessagePtr&& message) {
   293→  callbacks_->onComplete(toResponse(std::move(message)));
   294→  callbacks_ = nullptr;
   295→}
   296→
   297→void RawHttpClientImpl::onFailure(const Http::AsyncClient::Request&,
   298→                                  Http::AsyncClient::FailureReason reason) {
   299→  // TODO(botengyao): handle different failure reasons.
   300→  ASSERT(reason == Http::AsyncClient::FailureReason::Reset ||
   301→         reason == Http::AsyncClient::FailureReason::ExceedResponseBufferLimit);
   302→  callbacks_->onComplete(std::make_unique<Response>(errorResponse()));
   303→  callbacks_ = nullptr;
   304→}
